// Build reverse lookup: callingCode -> country ISO
export const CALLING_CODE_MAP = {};
for (const [iso, data] of Object.entries(COUNTRIES)) {
  const code = data.callingCode;
  if (!CALLING_CODE_MAP[code]) CALLING_CODE_MAP[code] = [];
  CALLING_CODE_MAP[code].push(iso);
}

export function getCountryByISO(iso) {
  return COUNTRIES[iso?.toUpperCase()] || null;
}

export function getCountryByCallingCode(callingCode) {
  const isoList = CALLING_CODE_MAP[callingCode];
  if (!isoList || isoList.length === 0) return null;
  return { iso: isoList[0], ...COUNTRIES[isoList[0]] };
}
